        }

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

### gRPC Server 구현체

파일 위치: `{profile-module}/src/main/kotlin/com/maum/backend/controller/ProfileGrpcService.kt`

```kotlin
@GrpcService
class ProfileGrpcService(
    private val profileDomainService: ProfileDomainService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun getProfile(
        request: GetProfileRequest,
        responseObserver: StreamObserver<GetProfileResponse>,
    ) {
        val profile = profileDomainService.getProfile(request.userId)
        val response = GetProfileResponse.newBuilder()
            .setProfile(profile.toProto())
            .build()
        responseObserver.onNext(response)
        responseObserver.onCompleted()
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        // 유효성 검증
        if (request.hasNickname() && (request.nickname.length < 2 || request.nickname.length > 20)) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription("닉네임은 2~20자 이내여야 합니다")
                    .asException()
            )
            return
        }
        if (request.hasBio() && request.bio.length > 200) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription("자기소개는 200자 이내여야 합니다")
                    .asException()
            )
            return
        }
        if (request.hasAge() && request.age < 18) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription("나이는 18세 이상이어야 합니다")
                    .asException()
            )
            return
        }
        if (request.updateInterests && request.interestsList.size > 10) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription("관심사는 최대 10개까지 설정할 수 있습니다")
                    .asException()
            )
            return
        }

        val updated = profileDomainService.updateProfile(request)
        val response = UpdateProfileResponse.newBuilder()
            .setProfile(updated.toProto())
            .build()
        responseObserver.onNext(response)
        responseObserver.onCompleted()
    }
}
